"use strict";(self.webpackChunkheidelbergman_site=self.webpackChunkheidelbergman_site||[]).push([[673],{7994:e=>{e.exports=JSON.parse('[{"id":"/2026/07/23/strecken-sperrungen","metadata":{"permalink":"/blog/2026/07/23/strecken-sperrungen","source":"@site/blog/2026-07-23-strecken-sperrungen.md","title":"Strecken-Sperrungen Heidelberg Triathlon 2026","description":"Strecken-Sperrungen Heidelberg Triathlon 2026","date":"2026-07-23T00:00:00.000Z","formattedDate":"23. Juli 2026","tags":[],"hasTruncateMarker":false,"authors":[{"name":"Orga Team","title":"Heidelberg-Triathlon Orga Team","imageURL":"https://www.heidelberg-triathlon.de/img/logo/HDtri_round_mini.png","key":"orga"}],"frontMatter":{"title":"Strecken-Sperrungen Heidelberg Triathlon 2026","authors":["orga"]},"unlisted":false,"nextItem":{"title":"TauschZone beim Heidelberg Triathlon 2026","permalink":"/blog/2026/07/20/tauschzone"}},"content":"![Strecken-Sperrungen Heidelberg Triathlon 2026](/blog/2026_07_23_sperrungen_cover.png)\\n\\nLiebe Athlet\\\\*innen, liebe Zuschauer\\\\*innen, liebe Anwohner\\\\*innen,\\n\\nam Sonntag, den **26.07.2026**, findet der Heidelberg Triathlon statt. Wir freuen uns auf ein gro\xdfes Event und viele Zuschauer\\\\*innen. Damit der Wettkampf f\xfcr alle Beteiligten reibungslos abl\xe4uft, bitten wir um Verst\xe4ndnis f\xfcr die notwendigen Strecken-Sperrungen. Im Folgenden findet Ihr eine \xdcbersicht \xfcber die Sperrungen der einzelnen Disziplinen.\\n\\n## Schwimmen \u2014 Stra\xdfensperrungen 8:00 \u2013 10:30 Uhr\\n\\n- **Sperrung der B37** im Bereich zwischen Theodor-Heuss-Br\xfccke & Karlstor\\n- Aufhebung der Sperrung West-Ost ab ca. 10:15 Uhr\\n- Aufhebung der Sperrung Ost-West ab ca. 10:30 Uhr\\n- **Umleitung** \xfcber Schlossbergtunnel\\n\\n## Radfahren \u2014 Stra\xdfensperrungen 6:00 \u2013 14:00 Uhr\\n\\n- **L534** in Richtung Heidelberg von 8:00 Uhr bis ca. 14:00 Uhr gesperrt\\n- **Ziegelh\xe4user & Neuenheimer Landstra\xdfe** von 8:00 Uhr bis 14:00 Uhr beidseitig gesperrt\\n- **Uferstra\xdfe** ab 6:00 Uhr beidseitig gesperrt\\n- **Alte Br\xfccke** auf den seitlichen Gehwegen eingeschr\xe4nkt \xfcberquerbar\\n- **Keine Zufahrt zum K\xf6nigstuhl** von Gaiberg & Waldhilsbach ab 7:00 Uhr bis 13:00 Uhr\\n- **Keine Zufahrt zum Schloss & K\xf6nigstuhl** \xfcber Klingenteichstra\xdfe & Schloss-Wolfsbrunnenweg ab 8:30 Uhr\\n- **Achtung: Strecke f\xfchrt durch Altstadt!**\\n\\n## Laufen \u2014 Stra\xdfensperrungen 6:00 \u2013 14:00 Uhr\\n\\n- **Uferstra\xdfe** ab 6:00 Uhr beidseitig gesperrt\\n- **Br\xfcckenkopfstra\xdfe** ab 9:00 Uhr bis ca. 14:00 Uhr beidseitig gesperrt\\n- **Bergstra\xdfe** ab 9:00 Uhr bis 14:00 Uhr zwischen Br\xfcckenkopfstra\xdfe und Eingang Philosophenweg gesperrt\\n- **Philosophenweg** ab 9:00 Uhr bis 14:00 Uhr gesperrt\\n- Philosophenweg fu\xdfl\xe4ufig \xfcber Albert-\xdcberle-Str. & Schlangenweg erreichbar\\n\\n**Vielen Dank f\xfcr Eure R\xfccksichtnahme & Euer Verst\xe4ndnis!**\\n\\n![Sperrungen Schwimmen](/blog/2026_07_23_sperrungen_schwimmen.png)\\n\\n![Sperrungen Radfahren](/blog/2026_07_23_sperrungen_rad.png)\\n\\n![Sperrungen Laufen](/blog/2026_07_23_sperrungen_laufen.png)"},{"id":"/2026/07/20/tauschzone","metadata":{"permalink":"/blog/2026/07/20/tauschzone","source":"@site/blog/2026-07-20-tauschzone.md","title":"TauschZone beim Heidelberg Triathlon 2026","description":"TauschZone beim Heidelberg Triathlon 2026","date":"2026-07-20T00:00:00.000Z","formattedDate":"20. Juli 2026","tags":[],"hasTruncateMarker":false,"authors":[{"name":"Orga Team","title":"Heidelberg-Triathlon Orga Team","imageURL":"https://www.heidelberg-triathlon.de/img/logo/HDtri_round_mini.png","key":"orga"}],"frontMatter":{"title":"TauschZone beim Heidelberg Triathlon 2026","authors":["orga"]},"unlisted":false,"prevItem":{"title":"Strecken-Sperrungen Heidelberg Triathlon 2026","permalink":"/blog/2026/07/23/strecken-sperrungen"},"nextItem":{"title":"Race News","permalink":"/blog/2026/06/30/_race_news2"}},"content":"![TauschZone beim Heidelberg Triathlon 2026](/blog/2026_07_20_tauschzone.png)\\n\\nGib Deinem alten Triathlon-Equipment eine neue B\xfchne: Beim Heidelberg Triathlon erwartet Dich unsere **TauschZone f\xfcr gut erhaltene Sportausr\xfcstung**!\\n\\nJetzt bist Du dran: R\xe4um Deinen Schrank aus und entdecke, was bei Dir noch schlummert. Neoprenanzug, Laufschuhe oder Zubeh\xf6r \u2013 alles, was noch top in Schuss ist, bekommt hier eine neue Chance.\\n\\n## Spenden oder verkaufen: Du entscheidest!\\n\\nUnterst\xfctze unser Nachhaltigkeitskonzept mit Deiner Spende oder profitiere selbst vom Verkauf Deiner Ausr\xfcstung. So wird aus ungenutztem Equipment echte Nachhaltigkeit im Sport. Bringe Deine Artikel einfach vorbei, den Verkauf \xfcbernehmen wir f\xfcr Dich.\\n\\n## Zeiten\\n\\n- **Verkauf:** Samstag, 25.07.2026, von 17:00 bis 20:00 Uhr\\n- **Abgabe:** ab 16:30 Uhr\\n- **Abholung nicht verkaufter Gegenst\xe4nde und des Erl\xf6ses:** bis 20:30 Uhr\\n\\nKennzeichne Deine Artikel selbst mit Deinem Namen, Deiner Handynummer, dem Preis und der Angabe \u201eVerkauf\u201c oder \u201eSpende\u201c.\\n\\n**Bitte denke daran, bis 20:30 Uhr noch einmal bei der TauschZone vorbeizuschauen, um nicht verkaufte Artikel wieder mitzunehmen.**\\n\\n## Was nehmen wir an?\\n\\n- Bekleidung und Equipment f\xfcr die drei Triathlon-Disziplinen\\n- Trainings- und Wettkampfequipment, sofern die Artikel in einem guten und funktionsf\xe4higen Zustand sind\\n- Zum Beispiel: Radhosen, Radtrikots, Windjacken, Startnummernb\xe4nder, Laufkappis, Rucks\xe4cke, Badekappen, Trainingsuhren, Triathlonliteratur und Trinkflaschen"},{"id":"/2026/06/30/_race_news2","metadata":{"permalink":"/blog/2026/06/30/_race_news2","source":"@site/blog/2026-06-30_race_news2.md","title":"Race News","description":"Staffel","date":"2026-06-30T00:00:00.000Z","formattedDate":"30. Juni 2026","tags":[],"hasTruncateMarker":false,"authors":[{"name":"Orga Team","title":"Heidelberg-Triathlon Orga Team","imageURL":"https://www.heidelberg-triathlon.de/img/logo/HDtri_round_mini.png","key":"orga"}],"frontMatter":{"title":"Race News","authors":["orga"]},"unlisted":false,"prevItem":{"title":"TauschZone beim Heidelberg Triathlon 2026","permalink":"/blog/2026/07/20/tauschzone"},"nextItem":{"title":"Streckenchecks","permalink":"/blog/2026/05/12/_streckenchecks"}},"content":"![Staffel](/img/banner/Radfahren.png)\\n\\n\\n### Last minute Startpl\xe4tze\\nWie bitte? Es gibt noch Startpl\xe4tze? Durch gl\xfcckliche Umst\xe4nde k\xf6nnen wir noch wenige Einzel- sowie Staffel-Startpl\xe4tze zur Verf\xfcgung stellen. **F\xfcr diese wird die Anmeldung am 03. Juli um 18 Uhr noch einmal \xf6ffnen.** Es gilt \\"first come, first serve\\". Also, spread the word \u2013 vielleicht wartet in eurem Bekanntenkreis ja noch jemand auf diese Gelegenheit.\\n\\n> **WICHTIG:** Die Anmeldung muss bis zum **05. Juli vollst\xe4ndig eingegangen** sein.\\n\\n---\\n\\n### Streckenchecks und Community Events\\n\\n* **07. Juli:** Radstreckencheck mit ***ACE Endurance Coaching*** * *Treffpunkt:* 18 Uhr, Uferstra\xdfe 4  \\n* **15. Juli:** Radstreckencheck  \\n  * Im Anschluss: *Snacks & Drinks im 15High bei unserem Partner **Atlantic Hotel.*** * *Treffpunkt:* 18 Uhr, Uferstra\xdfe 4. Bitte bringt ein Fahrradschloss mit.  \\n\\nF\xfcr unsere Planung haben wir bei manchen Streckenchecks und Community Events eine Anmeldung eingerichtet. Klickt dazu einfach unten auf den Link! Wir freuen uns, euch bei den Events dabei zu haben!\\n\\n\ud83d\udc49 [Zur Anmeldung f\xfcr die Streckenchecks](https://docs.google.com/forms/d/e/1FAIpQLScNWz9wJsXdUYg0mqryB-v2rUeIqcI1IWhcOUKwo1IbxMLIAw/viewform)\\n\\n---\\n\\n### Ummeldungen sind noch bis zum 05. Juli m\xf6glich\\nIhr k\xf6nnt dieses Jahr leider doch nicht teilnehmen und wollt euren Startplatz nun weitergeben? Die Ummeldung ist noch **bis zum 05. Juli um 23:59 Uhr** m\xf6glich. \\n\\nMeldet euch daf\xfcr bitte mit der einspringenden Person in CC per Mail unter [anmeldung@heidelberg-triathlon.de](mailto:anmeldung@heidelberg-triathlon.de). Die Ummeldegeb\xfchr betr\xe4gt 20 Euro.\\n\\n---\\n\\n### Helfer*innen gesucht!\\nWir sind nach wie vor auf der Suche nach **helfenden H\xe4nden** f\xfcr den Wettkampftag \u2013 **insbesondere auf der Rad- und Laufstrecke.** Fragt gerne in eurem Freundes- und Bekanntenkreis herum, ob nicht jemand Zeit und Lust h\xe4tte, uns bei der Organisation und euch sowie alle anderen Athlet*innen auf der Strecke zu unterst\xfctzen. \\n\\nF\xfcr alle Helfenden gibt es als Dankesch\xf6n nicht nur Verpflegung am Vorabend bei der **Pastaparty** und am Wettkampftag und ein **Shirt**, sondern auch **einen gratis Monat Training bei unserem Hauptsponsor aera Fitness & Health Club.**\\n\\n\ud83d\udc49 [Zur Helferanmeldung](https://lukify.app/vjmzyp)\\n\\n---\\n\\n### Noch auf der Suche nach einer \xdcbernachtungsm\xf6glichkeit?\\nFreundlicherweise werden wir auch dieses Jahr vom **Atlantic Hotel** unterst\xfctzt. Dieses bietet euch einen **reduzierten Preis** f\xfcr die \xdcbernachtung in Heidelberg am Wettkampfwochenende. Details dazu folgen in wenigen Tagen.\\n\\n---\\n\\n## Viel Freude beim Training w\xfcnscht das Orga-Team!"}]')}}]);